package jetbrains.mps.baseLanguage.unitTest.execution.server;

/*Generated by MPS */

import org.junit.runner.Request;
import jetbrains.mps.baselanguage.unitTest.execution.launcher.JUnit4TestContributor;
import jetbrains.mps.testbench.junit.runners.PushEnvironmentRunnerBuilder;
import jetbrains.mps.tool.environment.Environment;
import jetbrains.mps.project.MPSProject;
import jetbrains.mps.baseLanguage.unitTest.execution.client.ITestNodeWrapper;
import org.jetbrains.annotations.NotNull;
import org.jetbrains.mps.openapi.module.SModule;
import org.junit.runner.Description;
import jetbrains.mps.module.ModuleClassLoaderIsNullException;

/**
 * Knows how to launch TransformationTest with TestRunner suited for in-process test execution
 * XXX similar to ScriptTestContributor (for tests executed from command line), although unlike STE supports individual test methods.
 */
public class NodeWrappersTestsContributor extends AbstractInProcessTestContributor<Request> implements JUnit4TestContributor {
  private final PushEnvironmentRunnerBuilder myRunnerBuilder;

  public NodeWrappersTestsContributor(Environment env, MPSProject mpsProject, String runConfigurationName, Iterable<? extends ITestNodeWrapper> testNodes) {
    super(mpsProject, runConfigurationName, testNodes);
    myRunnerBuilder = new PushEnvironmentRunnerBuilder(env);
  }

  @Override
  public Iterable<Request> gatherTests() {
    //  FIXME review if I can make use of AbstractTestConverter logic here (not to duplicate).
    //       FWIW, InProcessExecutionFilter could be applied before transfigure(), and ITestNodeWrapper easily transforms into TestRecord
    return collect();
  }

  @NotNull
  @Override
  protected Request processTestCase(ITestNodeWrapper testNode, SModule testModule, String fqName) {
    try {
      return requestForTestClass(fqName, testModule);
    } catch (ClassNotFoundException e) {
      notifyByBaloonCLNF(e, testNode);
      return createFailedTestForClass(fqName, e);
    } catch (Exception e) {
      return createFailedTestForClass(fqName, e);
    }
  }

  @NotNull
  @Override
  protected Request processTestMethod(ITestNodeWrapper testNode, SModule testModule, String fqName) {
    int index = fqName.lastIndexOf('.');
    String testFqName = fqName.substring(0, index);
    String methodName = fqName.substring(index + 1);
    try {
      final Request classRequest = requestForTestClass(testFqName, testModule);
      return classRequest.filterWith(Description.createTestDescription(testFqName, methodName));
    } catch (ClassNotFoundException e) {
      notifyByBaloonCLNF(e, testNode);
      return createFailedTestForMethod(testFqName, methodName, e);
    } catch (Exception e) {
      return createFailedTestForMethod(testFqName, methodName, e);
    }
  }

  @Override
  @NotNull
  protected Request createFailedTestForClass(String fqName, Exception e) {
    return Request.runner(new AssumptionFailedRunner(e, Description.createSuiteDescription(fqName)));
  }

  @NotNull
  @Override
  protected Request createFailedTestForMethod(String testFqName, String methodName, Exception e) {
    return Request.runner(new AssumptionFailedRunner(e, Description.createTestDescription(testFqName, methodName)));
  }

  private Request requestForTestClass(String fqName, SModule module) throws ClassNotFoundException, ModuleClassLoaderIsNullException {
    final Class<?> aClass = loadTestClass(fqName, module);
    return Request.runner(myRunnerBuilder.safeRunnerForClass(aClass));
  }
}
